// NeuConX — Markdown renderer v5
// Aggressive reconstruction of collapsed AI output (newlines stripped from storage)
(function(root){

  function preprocess(src){
    // ── Step 1: Extract headers from mid-text ──────────────────────────────────
    // "### Title" appearing after non-newline content → break before it
    src = src.replace(/([^\n#])\s*(#{1,6} [A-Z"'\(])/g, '$1\n\n$2');

    // ── Step 2: Expand inline numbered lists to separate lines ─────────────────
    // "1. text 2. text 3. text" → proper lines
    // Match ". " only when preceded by a digit and followed by bold or capital
    src = src.replace(/(\d+\.) ([^.]+?)(?= \d+\. [A-Z\*\[]|$)/g, function(_,num,text){
      return num + ' ' + text.trim() + '\n';
    });
    // Another pass: handle "text. 1. **Bold**" pattern
    src = src.replace(/([a-z\.\!\?\"\')\*_])\s+(\d+\.) /g, '$1\n\n$2 ');

    // ── Step 3: Expand inline bullet lists ────────────────────────────────────
    // "* Item1 * Item2" on same line → separate lines
    src = src.replace(/(\S)\s+\* ([A-Z\*\["])/g, '$1\n* $2');

    // ── Step 4: Section breaks ─────────────────────────────────────────────────
    src = src.replace(/([^\n]) (---+) /g, '$1\n\n$2\n\n');
    src = src.replace(/([^\n])(---+)/g, '$1\n\n$2\n\n');

    // ── Step 5: Blank line hygiene ─────────────────────────────────────────────
    src = src.replace(/([^\n])\n(#{1,6} )/g, '$1\n\n$2');
    src = src.replace(/(#{1,6} [^\n]+)\n([^#\n])/g, '$1\n\n$2');
    // Blank line before bullet/numbered lists
    src = src.replace(/([^\n\-\*\d])\n([-\*\+] |\d+\. )/g, '$1\n\n$2');

    return src;
  }

  function marked(src){
    if(!src) return '';
    src = src.replace(/\r\n/g,'\n').replace(/\r/g,'\n');
    src = preprocess(src);

    // Code blocks
    const codeBlocks=[];
    src = src.replace(/```(\w*)\n?([\s\S]*?)```/g,function(_,lang,code){
      const esc=code.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
      codeBlocks.push('<pre><code'+(lang?' class="language-'+lang+'"':'')+'>'
        +esc.trim()+'</code></pre>');
      return '\n\n\x00CB'+(codeBlocks.length-1)+'\x00\n\n';
    });

    const blocks = src.split(/\n{2,}/);

    const out = blocks.map(function(block){
      block = block.trim();
      if(!block) return '';

      const cbm=block.match(/^\x00CB(\d+)\x00$/);
      if(cbm) return codeBlocks[+cbm[1]];

      // Heading (single line)
      const lines=block.split('\n');
      if(lines.length===1){
        const hm=block.match(/^(#{1,6})\s+(.+)$/);
        if(hm) return '<h'+hm[1].length+'>'+inl(hm[2].trim())+'</h'+hm[1].length+'>';
      }

      if(/^> /.test(block))
        return '<blockquote>'+marked(block.replace(/^> ?/gm,''))+'</blockquote>';

      if(/^([-*_]\s*){3,}$/.test(block)) return '<hr>';

      // Table
      if(lines.length>=2&&/\|/.test(lines[0])&&/\|[\s\-:]+\|/.test(lines[1])){
        const ths=lines[0].split('|').map(c=>c.trim()).filter(Boolean).map(c=>'<th>'+inl(c)+'</th>').join('');
        const trs=lines.slice(2).map(function(r){
          const tds=r.split('|').map(c=>c.trim()).filter(Boolean).map(c=>'<td>'+inl(c)+'</td>').join('');
          return tds?'<tr>'+tds+'</tr>':'';
        }).filter(Boolean).join('');
        return '<table><thead><tr>'+ths+'</tr></thead><tbody>'+trs+'</tbody></table>';
      }

      // Unordered list
      if(lines.every(l=>!l.trim()||/^[-*+]\s/.test(l.trim()))&&/^[-*+]\s/.test(lines[0].trim())){
        const lis=lines.filter(l=>l.trim()).map(l=>
          '<li>'+inl(l.trim().replace(/^[-*+]\s+/,''))+'</li>').join('');
        return '<ul>'+lis+'</ul>';
      }

      // Ordered list
      if(lines.every(l=>!l.trim()||/^\d+[\.\)]\s/.test(l.trim()))&&/^\d+[\.\)]\s/.test(lines[0].trim())){
        const lis=lines.filter(l=>l.trim()).map(l=>
          '<li>'+inl(l.trim().replace(/^\d+[\.\)]\s+/,''))+'</li>').join('');
        return '<ol>'+lis+'</ol>';
      }

      // Mixed block — some lines are list items, some prose
      // Render each line individually
      const rendered = lines.map(function(line){
        line = line.trim();
        if(!line) return '';
        if(/^[-*+]\s/.test(line)) return '<li class="inline-li">'+inl(line.replace(/^[-*+]\s+/,''))+'</li>';
        if(/^\d+[\.\)]\s/.test(line)) return '<li class="inline-oli">'+inl(line.replace(/^\d+[\.\)]\s+/,''))+'</li>';
        return inl(line);
      }).join('<br>');
      return '<p>'+rendered+'</p>';
    });

    return out.filter(Boolean).join('\n');
  }

  function inl(t){
    if(!t) return '';
    const ic=[];
    t=t.replace(/`([^`\n]+)`/g,function(_,c){
      ic.push('<code>'+c.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')+'</code>');
      return '\x00IC'+(ic.length-1)+'\x00';
    });
    t=t.replace(/&(?!(amp|lt|gt|quot|#);)/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    t=t.replace(/\*{3}([^*\n]+?)\*{3}/g,'<strong><em>$1</em></strong>');
    t=t.replace(/\*{2}([^*\n]+?)\*{2}/g,'<strong>$1</strong>');
    t=t.replace(/\*([^*\s\n][^*\n]*?)\*/g,'<em>$1</em>');
    t=t.replace(/_{2}([^_\n]+?)_{2}/g,'<strong>$1</strong>');
    t=t.replace(/_([^_\s\n][^_\n]*?)_/g,'<em>$1</em>');
    t=t.replace(/~~([^~\n]+?)~~/g,'<del>$1</del>');
    t=t.replace(/\[([^\]]+)\]\(([^)]+)\)/g,'<a href="$2" target="_blank" rel="noopener">$1</a>');
    t=t.replace(/\x00IC(\d+)\x00/g,(_,i)=>ic[+i]);
    return t;
  }

  marked.parse=marked; marked.setOptions=function(){};
  if(typeof module!=='undefined') module.exports=marked;
  else root.marked=marked;
})(this);